package main

import (
    "fmt"
)

func main() {
    // ---- Creating maps ----
    var m1 map[string]int
    m2 := make(map[string]int)
    m3 := map[string]int{
        "Hero":    100,
        "Aragorn": 85,
        "Gandalf": 95,
    }

    fmt.Println("m1:", m1)
    fmt.Println("m2:", m2)
    fmt.Println("m3:", m3)

    // ---- Adding/updating values ----
    scores := make(map[string]int)
    scores["Hero"] = 100
    scores["Aragorn"] = 85
    scores["Hero"] = 120  // Updates

    fmt.Println("Scores:", scores)

    // ---- Accessing values ----
    heroScore := scores["Hero"]
    fmt.Println("Hero's score:", heroScore)

    // ---- Check if key exists ----
    score, ok := scores["Legolas"]
    if ok {
        fmt.Println("Legolas's score:", score)
    } else {
        fmt.Println("Legolas not found")
    }

    // ---- Deleting keys ----
    delete(scores, "Aragorn")
    fmt.Println("After delete:", scores)

    // ---- Iterating over map ----
    fmt.Println("\n=== Iterating ===")
    for name, score := range scores {
        fmt.Printf("%s: %d\n", name, score)
    }

    // ---- Map with struct values ----
    type Player struct {
        Health int
        Level  int
    }

    players := map[string]Player{
        "Hero":    {Health: 100, Level: 5},
        "Aragorn": {Health: 120, Level: 8},
    }

    fmt.Println("\nPlayers:", players)

    // ---- Map length ----
    fmt.Println("Number of players:", len(players))

    // ---- Zero values ----
    // Accessing a non-existent key returns the zero value
    fmt.Println("Non-existent score:", scores["Frodo"])

    // ---- Nil map ----
    var m4 map[string]int
    if m4 == nil {
        fmt.Println("m4 is nil")
    }
    // m4["key"] = 1  // ERROR! Panic
}

