phase3.solution:
package main

import "fmt"

func main() {
    scores := map[string]int{
        "Hero":    100,
        "Aragorn": 85,
        "Gandalf": 95,
    }
    fmt.Println("Initial:", scores)

    scores["Hero"] = 120
    fmt.Println("After update:", scores)

    _, ok := scores["Legolas"]
    if !ok {
        fmt.Println("Legolas not found")
    }

    delete(scores, "Aragorn")
    fmt.Println("Final:", scores)
}
